import { GoogleGenAI, Type } from "@google/genai";
import { Memory } from './types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `Du er en personlig biograf for en musiker og forfatter.
Din opgave er at lytte til lydoptagelser af livserindringer og transformere dem til litterær prosa.
Bevar brugerens unikke stemme: reflekterende, rytmisk, poetisk og med en forfatters øje for detaljer.
Du skal:
1. Transkribere indholdet præcist.
2. Omformulere det til en smuk, sammenhængende tekst, der lyder som et kapitel i en erindringsbog.
3. Kategorisere mindet i et tema (f.eks. 'Tanker fra en mand', 'Musikkens Ekko', 'Barndommens Gader').
4. Returnere resultatet som JSON.`;

export const processMemory = async (audioBase64: string): Promise<Partial<Memory>> => {
  const model = ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "audio/webm",
              data: audioBase64
            }
          },
          {
            text: "Analyser denne lydfil og transformer den til et litterært minde."
          }
        ]
      }
    ],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          originalTranscription: { type: Type.STRING },
          polishedText: { type: Type.STRING },
          theme: { type: Type.STRING },
        },
        required: ["originalTranscription", "polishedText", "theme"]
      }
    }
  });

  const response = await model;
  const result = JSON.parse(response.text || "{}");
  return result;
};

