};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, Music } from 'lucide-react';

interface RecorderProps {
  onRecordingComplete: (base64: string, blob: Blob) => void;
  isProcessing: boolean;
}

const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          onRecordingComplete(base64, blob);
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setDuration(0);
      timerRef.current = setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error("Kunne ikke starte optagelse:", err);
      alert("Giv venligst tilladelse til mikrofonen.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col items-center gap-4">
      <div className="flex items-center gap-6">
        {!isRecording ? (
          <button
            onClick={startRecording}
            disabled={isProcessing}
            className="w-16 h-16 rounded-full bg-amber-600 hover:bg-amber-500 flex items-center justify-center transition-all shadow-lg hover:scale-105 disabled:opacity-50"
          >
            <Mic className="text-white w-8 h-8" />
          </button>
        ) : (
          <button
            onClick={stopRecording}
            className="w-16 h-16 rounded-full bg-red-600 animate-pulse flex items-center justify-center transition-all shadow-lg"
          >
            <Square className="text-white fill-current w-6 h-6" />
          </button>
        )}
      </div>

      {isRecording && (
        <div className="flex flex-col items-center gap-2">
            <span className="text-amber-400 font-mono text-xl">{formatTime(duration)}</span>
            <div className="flex gap-1">
                {[...Array(5)].map((_, i) => (
                    <div 
                        key={i} 
                        className="w-1 bg-amber-500 rounded-full animate-bounce" 
                        style={{ height: '12px', animationDelay: `${i * 0.1}s` }}
                    />
                ))}
            </div>
        </div>
      )}

      {isProcessing && (
        <div className="flex items-center gap-2 text-amber-200">
          <Loader2 className="animate-spin w-5 h-5" />
          <span className="text-sm font-medium italic">Biografen skriver dine ord ned...</span>
        </div>
      )}
    </div>
  );
};

export default Recorder;

import React from 'react';
import { Memory, Chapter } from '../types';
import { BookOpen, Calendar, Trash2 } from 'lucide-react';

interface BookShelfProps {
  memories: Memory[];
  onDelete: (id: string) => void;
}

const BookShelf: React.FC<BookShelfProps> = ({ memories, onDelete }) => {
  const themes = Array.from(new Set(memories.map(m => m.theme)));

  const organizedMemories: Chapter[] = themes.map(theme => ({
    title: theme,
    description: `En samling af tanker om ${theme.toLowerCase()}.`,
