      <footer className="py-6 text-center text-slate-600 text-[10px] uppercase tracking-[0.3em] font-medium opacity-50">
        &copy; {new Date().getFullYear()} Biografen &bull; Stemmens Arkiv
      </footer>
    </div>
  );
};

