  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/webm",
            data: audioBase64
          }
        },
        {
          text: "Analyser denne lydfil og transformer den til et litterært minde."
        }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          originalTranscription: { type: Type.STRING },
          polishedText: { type: Type.STRING },
          theme: { type: Type.STRING },
        },
        required: ["originalTranscription", "polishedText", "theme"]
      }
    }
  });

  // Access .text property directly (it's a property, not a method)
  const result = JSON.parse(response.text || "{}");
  return result;
};

