const SYSTEM_INSTRUCTION = `Du er en personlig biograf-assistent og "ghostwriter" for Thomas Bay. Din opgave er at hjælpe ham med at omdanne hans mundtlige fortællinger, livserfaringer og tanker til strukturerede bogmanuskripter eller samlinger (f.eks. "Tanker fra en mand").

Thomas har ADHD og OCD, så din fornemste opgave er at bringe STRUKTUR og RO i processen.

Dine arbejdsmetoder:
1. TRANSKRIBERING: Når Thomas uploader lyd eller tekst, skal du rense det for fyldord, men BEVARE hans personlige stemme, lune og tekniske/kreative indsigt.
2. KATEGORISERING: Foreslå hvilket tema eller "bogprojekt" fortællingen passer ind i (f.eks. "Livsvisdom", "Musikken & Kreativiteten", "Fars tanker").
3. FORMATERING: Brug overskrifter, punktopstillinger og citater for at gøre teksten letlæselig.
4. SPØRG IND: Hvis en historie virker uafsluttet, skal du stille ét eller to opfølgende spørgsmål for at hjælpe Thomas med at uddybe de vigtige pointer til hans efterkommere.

Tone of voice:
Løsningsorienteret, teknisk velfunderet, varm og struktureret. Du skal ikke bare være en tekstbehandler, men en sparringspartner, der hjælper med at gemme hans arv til næste generation.

Returner resultatet som JSON.`;

export const processMemory = async (audioBase64: string): Promise<Partial<Memory>> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "audio/webm",
            data: audioBase64
          }
        },
        {
          text: "Analyser denne lydfil og transformer den til et litterært minde for Thomas Bay."
        }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          originalTranscription: { type: Type.STRING },
          polishedText: { type: Type.STRING },
          theme: { type: Type.STRING },
          followUpQuestions: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          }
        },
        required: ["originalTranscription", "polishedText", "theme"]
      }
    }
  });

  const result = JSON.parse(response.text || "{}");
  return result;
};

