import React, { useState, useEffect, useRef } from 'react';
import { Book, MessageCircle, Music, Feather, User, ChevronRight } from 'lucide-react';
import Recorder from './components/Recorder';
import BookShelf from './components/BookShelf';
import { Memory, ChatMessage, View } from './types';
import { processMemory } from './geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<View>('chat');
  const [memories, setMemories] = useState<Memory[]>([]);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      role: 'assistant',
      content: 'Goddag, Thomas. Jeg sidder klar med pennen. Lad os få bragt lidt struktur på tankerne i dag. Hvad har du på hjertet?'
    }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('biograf_memories');
    if (saved) setMemories(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('biograf_memories', JSON.stringify(memories));
  }, [memories]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleRecordingComplete = async (base64: string, blob: Blob) => {
    setIsProcessing(true);
    setChatHistory(prev => [...prev, { 
      role: 'user', 
      content: 'Sender lydoptagelse...', 
      isAudio: true 
    }]);

    try {
      const result = await processMemory(base64);

      if (result.polishedText) {
        const newMemory: Memory = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          originalTranscription: result.originalTranscription || '',
          polishedText: result.polishedText,
          theme: result.theme || 'Usorteret',
          audioUrl: URL.createObjectURL(blob),
          followUpQuestions: result.followUpQuestions
        };

        setMemories(prev => [newMemory, ...prev]);

        let assistantContent = `Jeg har arkiveret din fortælling under projektet **"${result.theme}"**:\n\n${result.polishedText}`;

        if (result.followUpQuestions && result.followUpQuestions.length > 0) {
          assistantContent += `\n\n---\n\n**For at uddybe historien, Thomas:**\n` + 
            result.followUpQuestions.map(q => `• ${q}`).join('\n');
        }

        setChatHistory(prev => [...prev, {
          role: 'assistant',
          content: assistantContent,
          memoryData: newMemory
        }]);
      }
    } catch (err) {
      setChatHistory(prev => [...prev, {
        role: 'assistant',
        content: 'Der opstod en lille teknisk forstyrrelse. Kan du prøve at gentage det sidste?'
      }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const deleteMemory = (id: string) => {
    if (confirm("Er du sikker på, at du vil slette dette minde?")) {
      setMemories(prev => prev.filter(m => m.id !== id));
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-5xl mx-auto px-4 sm:px-6">
      {/* Header */}
      <header className="py-8 flex justify-between items-center border-b border-slate-800">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-amber-900/20 rounded-lg">
            <Feather className="w-6 h-6 text-amber-500" />
          </div>
          <div>
            <h1 className="text-2xl font-serif font-bold tracking-tight text-amber-50">Thomas Bay</h1>
            <p className="text-xs text-slate-500 uppercase tracking-[0.2em] font-medium italic">Ghostwriter & Biograf</p>
          </div>
        </div>

        <nav className="flex items-center gap-2 glass p-1 rounded-xl">
          <button 
            onClick={() => setView('chat')}
            className={`px-4 py-2 rounded-lg flex items-center gap-2 transition-all ${view === 'chat' ? 'bg-amber-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <MessageCircle className="w-4 h-4" />
            <span className="hidden sm:inline font-medium text-sm">Samtale</span>
          </button>
          <button 
            onClick={() => setView('library')}
            className={`px-4 py-2 rounded-lg flex items-center gap-2 transition-all ${view === 'library' ? 'bg-amber-600 text-white' : 'text-slate-400 hover:text-slate-200'}`}
          >
            <Book className="w-4 h-4" />
            <span className="hidden sm:inline font-medium text-sm">Manuskripter</span>
          </button>
        </nav>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto py-8">
        {view === 'chat' ? (
          <div className="flex flex-col gap-8 pb-32">
            {chatHistory.map((msg, i) => (
              <div 
                key={i} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[90%] sm:max-w-2xl flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                  <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${msg.role === 'user' ? 'bg-slate-700' : 'bg-amber-900/30'}`}>
                    {msg.role === 'user' ? <User className="w-4 h-4" /> : <Feather className="w-4 h-4 text-amber-500" />}
                  </div>
                  <div className={`space-y-4 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    <div className={`p-6 rounded-2xl leading-relaxed whitespace-pre-wrap shadow-xl ${msg.role === 'user' ? 'bg-amber-700 text-white rounded-tr-none' : 'glass text-slate-200 rounded-tl-none border-l-4 border-l-amber-500/50'}`}>
                        {msg.isAudio && <div className="flex items-center gap-2 mb-2 italic text-xs opacity-70"><Music className="w-3 h-3"/> Modtager din stemme...</div>}
                        <div className={msg.role === 'assistant' ? 'serif text-lg leading-relaxed' : ''}>
                          {msg.content.split('\n').map((line, idx) => (
                            <p key={idx} className={line.startsWith('#') ? 'text-amber-400 font-bold mb-2 mt-4 text-xl' : 'mb-2'}>
                              {line}
                            </p>
                          ))}
                        </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
        ) : (
          <BookShelf memories={memories} onDelete={deleteMemory} />
        )}
      </main>

      {/* Sticky Recorder Bar (Chat View) */}
      {view === 'chat' && (
        <div className="fixed bottom-0 left-0 right-0 py-8 px-6 bg-gradient-to-t from-[#0f1115] via-[#0f1115]/95 to-transparent pointer-events-none">
          <div className="max-w-5xl mx-auto flex justify-center pointer-events-auto">
            <div className="glass p-5 rounded-3xl shadow-2xl w-full max-w-sm flex flex-col items-center border border-amber-500/20">
              <Recorder onRecordingComplete={handleRecordingComplete} isProcessing={isProcessing} />
              <p className="text-[10px] text-amber-500/60 uppercase tracking-[0.2em] mt-4 font-bold">Tryk for at fortælle næste kapitel</p>
            </div>
          </div>
        </div>
      )}

      {/* Footer Branding */}
      <footer className="py-4 text-center text-slate-700 text-[10px] uppercase tracking-[0.3em] font-medium">
        Thomas Bay &bull; Det Strukturerede Arkiv
      </footer>
    </div>
  );
};

export default App;

