import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, AlertCircle } from 'lucide-react';

interface RecorderProps {
  onRecordingComplete: (base64: string, blob: Blob) => void;
  isProcessing: boolean;
}

const Recorder: React.FC<RecorderProps> = ({ onRecordingComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [duration, setDuration] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  const startRecording = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Tjek for understøttede formater
      const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus') 
        ? 'audio/webm;codecs=opus' 
        : 'audio/webm';

      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunksRef.current, { type: mimeType });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          onRecordingComplete(base64, blob);
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start(1000); // Gem data hvert sekund
      setIsRecording(true);
      setDuration(0);
      timerRef.current = window.setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);
    } catch (err: any) {
      console.error("Mikrofon fejl:", err);
      let msg = "Kunne ikke få adgang til mikrofonen.";
      if (err.name === 'NotAllowedError') msg = "Adgang nægtet. Tjek dine browserindstillinger.";
      if (err.name === 'NotFoundError') msg = "Ingen mikrofon fundet på denne enhed.";
      setError(msg);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current !== null) {
        window.clearInterval(timerRef.current);
        timerRef.current = null;
      }
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  useEffect(() => {
    return () => {
      if (timerRef.current !== null) window.clearInterval(timerRef.current);
    };
  }, []);

  return (
    <div className="flex flex-col items-center gap-4 w-full">
      {error && (
        <div className="flex items-center gap-2 text-red-400 text-xs bg-red-900/20 p-2 rounded-lg mb-2">
          <AlertCircle className="w-3 h-3" />
          {error}
        </div>
      )}

      <div className="flex items-center gap-6">
        {!isRecording ? (
          <button
            onClick={startRecording}
            disabled={isProcessing}
            className="w-16 h-16 rounded-full bg-amber-600 hover:bg-amber-500 flex items-center justify-center transition-all shadow-lg hover:scale-105 disabled:opacity-50 disabled:grayscale"
          >
            <Mic className="text-white w-8 h-8" />
          </button>
        ) : (
          <button
            onClick={stopRecording}
            className="w-16 h-16 rounded-full bg-red-600 animate-pulse flex items-center justify-center transition-all shadow-lg"
          >
            <Square className="text-white fill-current w-6 h-6" />
          </button>
        )}
      </div>

      {isRecording && (
        <div className="flex flex-col items-center gap-2">
            <span className="text-amber-400 font-mono text-xl">{formatTime(duration)}</span>
            <div className="flex gap-1">
                {[...Array(5)].map((_, i) => (
                    <div 
                        key={i} 
                        className="w-1 bg-amber-500 rounded-full animate-bounce" 
                        style={{ height: '12px', animationDelay: `${i * 0.1}s` }}
                    />
                ))}
            </div>
        </div>
      )}

      {isProcessing && (
        <div className="flex items-center gap-2 text-amber-200">
          <Loader2 className="animate-spin w-5 h-5" />
          <span className="text-sm font-medium italic">Korrigerer dine ord...</span>
        </div>
      )}
    </div>
  );
};

export default Recorder;

