  context: { mode: 'new' | 'continuation', currentTheme?: string }
): Promise<Partial<Memory>> => {
  const prompt = context.mode === 'new' 
    ? "Dette er en NY historie. Analyser indholdet og foreslå et passende tema." 
    : `Dette er en FORTSÆTTELSE af projektet "${context.currentTheme}". Hold dig strikt til indholdet i denne optagelse og brug samme tema-navn.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: mimeType,
            data: audioBase64
          }
        },
        {
          text: `${prompt}\n\nGennemfør korrektur efter de strikse regler for Thomas Bay. Husk: Ingen digtning, brug [...] ved huller.`
        }
      ]
    },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          originalTranscription: { type: Type.STRING },
          polishedText: { type: Type.STRING },
          theme: { type: Type.STRING },
          followUpQuestions: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          }
        },
        required: ["originalTranscription", "polishedText", "theme"]
      }
    }
  });

  const text = response.text || "{}";
  try {
    return JSON.parse(text);
  } catch (e) {
    console.error("JSON Parse error:", text);
    throw new Error("Kunne ikke læse svaret fra biografen. Prøv venligst igen.");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Book, MessageCircle, Music, Feather, User, Upload, FileAudio, ChevronDown, PlusCircle } from 'lucide-react';
import Recorder from './components/Recorder';
import BookShelf from './components/BookShelf';
import { Memory, ChatMessage, View } from './types';
import { processMemory } from './geminiService';

const App: React.FC = () => {
  const [view, setView] = useState<View>('chat');
  const [memories, setMemories] = useState<Memory[]>([]);
  const [selectedTheme, setSelectedTheme] = useState<string>('new'); // 'new' or specific theme name
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([
    {
      role: 'assistant',
      content: 'Goddag, Thomas. Jeg sidder klar med pennen. Vælg et projekt forneden, eller start en helt ny historie. Hvad har du på hjertet?'
    }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Get unique themes for dropdown
  const themes = Array.from(new Set(memories.map(m => m.theme))).filter(Boolean);

  useEffect(() => {
    const saved = localStorage.getItem('biograf_memories');
    if (saved) setMemories(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('biograf_memories', JSON.stringify(memories));
  }, [memories]);

