    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64 = (reader.result as string).split(',')[1];
      processAudioData(base64, file, true);
    };
    reader.readAsDataURL(file);
    event.target.value = '';
  };

