                <FileAudio className="text-amber-500 w-5 h-5" />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer Branding */}
      <footer className="py-4 text-center text-slate-700 text-[10px] uppercase tracking-[0.3em] font-medium">
        Thomas Bay &bull; Det Strukturerede Arkiv
      </footer>
    </div>
  );
};

